  ('social-worker-moex-04005', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列何者不是幼兒時期的情緒概念內涵？', '["憤怒", "罪惡感", "驕傲", "親密感"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04006', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Piaget 的道德發展論中，將兒童道德發展分為三個階段，幼兒期依發展順序包含下列那二個 階段？', '["自律階段、他律階段", "無律階段、他律階段", "無律階段、自律階段", "他律階段、自律階段"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04007', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', 'Freud將人格結構分為三個部分，下列敘述何者正確？', '["本我：是人格的核心，受到現實原則的支配", "自我：為個人與生俱來的一種人格原始基礎，受唯樂原則支配", "超我：人格結構最高層，是後天學習而建立的，受到完美原則的支配", "自我：是人格的核心，受到完美原則支配"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04008', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列對於遊民（thehomeless）現象的敘述，何者錯誤？', '["他們是因為房價過高而無法購買，只能租房的人", "他們是沒有自己居所而住在公共空間的人", "他們可能面臨著與家庭成員關係的斷裂", "從家庭理論來說，他們在生命歷程中可能面臨著家庭危機或影響其生命的事件"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04009', 'social-worker', 'social-worker-moex-111-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '當前科技產品已然進入到生活日常，滑世代的現象影響著家庭及人際的互動，在考量親子關 係及家庭的生活品質，親子之間的共同因應方式，下列何者為佳？', '["家長應針對未成年兒少制定合宜的監控機制，但成年人可以不在此家庭規範內", "家庭成員可透過家庭會議建立家庭的規範並具體執行", "嚴禁在家中使用3C產品", "影響家庭親職的議題太多了，所以，不需要對於在家中運用3C產品的議題太擔心"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:23+00:00", "source_pdf_sha1": "0cea0105bd5f", "answer_pdf_sha1": "50abfa77128e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
